 1	import { Flex, FlexItem, Text, TextContent, TextVariants } from '@patternfly/react-core';
 2	import * as React from 'react';
 3	import { TopologyMetricPeer } from '../../../api/loki';
 4	import { Filter, FilterDefinition, Filters } from '../../../model/filters';
 5	import { NodeType } from '../../../model/flow-query';
 6	import { PeerResourceLink } from '../../tabs/netflow-topology/peer-resource-link';
 7	import { SummaryFilterButton } from '../../toolbar/filters/summary-filter-button';
 8	
 9	export interface ElementFieldProps {
10	  id: string;
11	  label: string;
12	  filterType: NodeType;
13	  forcedText?: string;
14	  peer: TopologyMetricPeer;
15	  filters: Filters;
16	  setFilters: (filters: Filter[]) => void;
17	  filterDefinitions: FilterDefinition[];
18	}
19	
20	export const ElementField: React.FC<ElementFieldProps> = ({
21	  id,
22	  label,
23	  filterType,
24	  forcedText,
25	  peer,
26	  filters,
27	  setFilters,
28	  filterDefinitions
29	}) => {
30	  return (
31	    <TextContent id={id} className="record-field-container">
32	      <Text component={TextVariants.h4}>{label}</Text>
33	      <Flex>
34	        <FlexItem flex={{ default: 'flex_1' }}>
35	          {forcedText ? <Text component="p">{forcedText}</Text> : <PeerResourceLink peer={peer} />}
36	        </FlexItem>
37	        <FlexItem>
38	          <SummaryFilterButton
39	            id={id + '-filter'}
40	            filters={filters}
41	            filterType={filterType}
42	            fields={peer}
43	            setFilters={setFilters}
44	            filterDefinitions={filterDefinitions}
45	          />
46	        </FlexItem>
47	      </Flex>
48	    </TextContent>
49	  );
50	};

